 * - A leading "00" international prefix is converted to "+".
 * - If no international prefix is present, defaultCountry is prepended.
 * - defaultCountry must be a digit string such as "1" or "+44".
 * - Extensions may be provided as "ext", "ext.", or "x" followed by digits.
 * - Empty input, missing digits, or unsupported characters throw an Error.
 */
function normalizePhoneNumber(input, defaultCountry) {
  if (typeof input !== 'string') {
    throw new Error('Phone number input must be a string');
  }

  const raw = input.trim();
  if (!raw) {
    throw new Error('Phone number input is empty');
  }

  if (typeof defaultCountry !== 'string' || !defaultCountry.trim()) {
    throw new Error('defaultCountry must be a non-empty string');
  }

  const normalizedCountry = defaultCountry.trim().replace(/^\+/, '');
  if (!/^\d+$/.test(normalizedCountry)) {
    throw new Error('defaultCountry must contain only digits, optionally prefixed with +');
  }

  const extensionMatch = raw.match(/(?:ext\.?|x)\s*(\d+)\s*$/i);
  const extension = extensionMatch ? extensionMatch[1] : '';
  const numberPart = extensionMatch ? raw.slice(0, extensionMatch.index).trim() : raw;

  if (/[A-WYZa-wyz]/.test(numberPart)) {
    throw new Error('Phone number contains invalid characters');
  }

  let normalized;
  if (numberPart.startsWith('+')) {
    const digits = numberPart.slice(1).replace(/\D/g, '');
    normalized = `+${digits}`;
  } else if (numberPart.startsWith('00')) {
    const digits = numberPart.slice(2).replace(/\D/g, '');
    normalized = `+${digits}`;
  } else {
    const digits = numberPart.replace(/\D/g, '');
    normalized = `+${normalizedCountry}${digits}`;
  }

  if (!/^\+\d+$/.test(normalized)) {
    throw new Error('Phone number must contain digits');
  }

  return extension ? `${normalized}x${extension}` : normalized;
}

module.exports = { normalizePhoneNumber };
