function flattenObject(obj) {
  if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {
    throw new TypeError('flattenObject expects a plain object');
  }

  const result = {};

  function walk(value, path) {
    if (value === null || typeof value !== 'object') {
      result[path] = value;
      return;
    }

    if (Array.isArray(value)) {
      if (value.length === 0) {
        result[path] = [];
        return;
      }

      value.forEach((item, index) => {
        walk(item, `${path}.${index}`);
      });
      return;
    }

    const keys = Object.keys(value);
    if (keys.length === 0) {
      result[path] = {};
      return;
    }

    for (const key of keys) {
      const nextPath = path ? `${path}.${key}` : key;
      walk(value[key], nextPath);
    }
  }

  const keys = Object.keys(obj);
  if (keys.length === 0) {
    return {};
  }

  for (const key of keys) {
    walk(obj[key], key);
  }

  return result;
}
```

**Array representation**
- Arrays use numeric indexes in the path.
- Example: `{ a: ['x', 'y'] }` becomes `{ 'a.0': 'x', 'a.1': 'y' }`.
- Empty arrays are preserved as the value at their path: `{ a: [] }` becomes `{ a: [] }`.
- Empty objects are also preserved: `{ a: {} }` becomes `{ a: {} }`.

