```js
function parseCsvLine(line) {
  if (typeof line !== 'string') {
    throw new TypeError('parseCsvLine: line must be a string');
  }

  if (line === '') {
    return [''];
  }

  const fields = [];
  let field = '';
  let inQuotes = false;
  let justClosedQuote = false;

  for (let i = 0; i < line.length; i++) {
    const ch = line[i];

    if (inQuotes) {
      if (ch === '"') {
        if (line[i + 1] === '"') {
          field += '"';
          i++;
        } else {
          inQuotes = false;
          justClosedQuote = true;
        }
      } else {
        field += ch;
      }
      continue;
    }

    if (ch === ',') {
      fields.push(field);
      field = '';
      justClosedQuote = false;
      continue;
    }

    if (ch === '"') {
      if (field.length === 0) {
        inQuotes = true;
        justClosedQuote = false;
      } else {
        throw new Error(`Malformed CSV: unexpected quote in unquoted field at index ${i}`);
      }
      continue;
    }

    if (justClosedQuote) {
      throw new Error(`Malformed CSV: unexpected character after closing quote at index ${i}`);
    }

    field += ch;
  }

  if (inQuotes) {
    throw new Error('Malformed CSV: unmatched quote');
  }

  fields.push(field);
  return fields;
}

module.exports = { parseCsvLine };
```

