function toTitleCase(input) {
  if (typeof input !== 'string' || input.length === 0) return '';

  let result = '';
  let shouldCapitalize = true;

  for (let i = 0; i < input.length; i++) {
    const char = input[i];
    const prev = i > 0 ? input[i - 1] : '';
    const isLetter = /[A-Za-z]/.test(char);
    const isBoundary = prev === '' || /[\s-]/.test(prev);
    const isApostropheContinuation = prev === "'" && i > 1 && /[A-Za-z]/.test(input[i - 2]);

    if (isLetter) {
      if (shouldCapitalize && !isApostropheContinuation) {
        result += char.toUpperCase();
      } else {
        result += char.toLowerCase();
      }
      shouldCapitalize = false;
    } else {
      result += char;
      shouldCapitalize = /[\s-]/.test(char);
    }

    if (isBoundary && isLetter && !isApostropheContinuation) {
      result = result.slice(0, -1) + char.toUpperCase();
      shouldCapitalize = false;
    }
  }

  return result;
}

module.exports = { toTitleCase };
