const assert = require('assert');
const { memoize } = require('./memoize');

describe('memoize', () => {
  it('caches primitive arguments', () => {
    let calls = 0;
    const fn = memoize((a, b) => {
      calls += 1;
      return a + b;
    });

    assert.strictEqual(fn(2, 3), 5);
    assert.strictEqual(fn(2, 3), 5);
    assert.strictEqual(calls, 1);
  });

  it('treats different argument values as different cache entries', () => {
    let calls = 0;
    const fn = memoize((a, b) => {
      calls += 1;
      return `${a}:${b}`;
    });

    assert.strictEqual(fn(1, 2), '1:2');
    assert.strictEqual(fn(2, 1), '2:1');
    assert.strictEqual(calls, 2);
  });

  it('preserves argument order in the cache key', () => {
    let calls = 0;
    const fn = memoize((...args) => {
      calls += 1;
      return args.join(',');
    });

    assert.strictEqual(fn('a', 'b', 'c'), 'a,b,c');
    assert.strictEqual(fn('a', 'c', 'b'), 'a,c,b');
    assert.strictEqual(calls, 2);
  });

  it('supports object arguments by reference identity', () => {
    let calls = 0;
    const fn = memoize((obj) => {
      calls += 1;
      return obj.value * 2;
    });

    const obj = { value: 4 };
    const sameShape = { value: 4 };

    assert.strictEqual(fn(obj), 8);
    assert.strictEqual(fn(obj), 8);
    assert.strictEqual(fn(sameShape), 8);
    assert.strictEqual(calls, 2);
  });

  it('caches undefined results', () => {
    let calls = 0;
    const fn = memoize((value) => {
      calls += 1;
      if (value === 'missing') return undefined;
      return value;
    });

    assert.strictEqual(fn('missing'), undefined);
    assert.strictEqual(fn('missing'), undefined);
    assert.strictEqual(calls, 1);
  });

  it('caches thrown errors for the same arguments', () => {
    let calls = 0;
    const error = new Error('boom');
    const fn = memoize((value) => {
      calls += 1;
      if (value === 0) throw error;
      return value;
    });

    assert.throws(() => fn(0), (err) => err === error);
    assert.throws(() => fn(0), (err) => err === error);
    assert.strictEqual(calls, 1);
  });

  it('preserves this when invoking the original function', () => {
    const obj = {
      factor: 3,
      multiply: memoize(function (value) {
        return value * this.factor;
      }),
    };

    assert.strictEqual(obj.multiply(5), 15);
    obj.factor = 10;
    assert.strictEqual(obj.multiply(5), 15);
  });

  it('supports zero-argument functions', () => {
    let calls = 0;
    const fn = memoize(() => {
      calls += 1;
      return 'ready';
    });

    assert.strictEqual(fn(), 'ready');
    assert.strictEqual(fn(), 'ready');
    assert.strictEqual(calls, 1);
  });

  it('distinguishes missing arguments from explicit undefined', () => {
    let calls = 0;
    const fn = memoize(function () {
      calls += 1;
      return arguments.length;
    });

    assert.strictEqual(fn(), 0);
    assert.strictEqual(fn(undefined), 1);
    assert.strictEqual(fn(), 0);
    assert.strictEqual(fn(undefined), 1);
    assert.strictEqual(calls, 2);
  });

  it('throws for non-function input', () => {
    assert.throws(() => memoize(null), /memoize expects a function/);
  });
});
```

**Cache key strategy**
- Uses a nested `Map` trie, one level per argument.
- Primitive values are keyed by value.
- Objects/functions are keyed by reference identity.
- Argument order matters because each position is a separate trie level.
- Zero-argument calls use the root node.
- `undefined` results are cached explicitly via a dedicated `RESULT` sentinel key.
- Thrown errors are also cached explicitly via a dedicated `ERROR` sentinel key.

