function slugify(input) {
  const transliterations = new Map([
    ['ß', 'ss'], ['ẞ', 'ss'],
    ['Æ', 'ae'], ['æ', 'ae'],
    ['Ø', 'o'], ['ø', 'o'],
    ['Å', 'a'], ['å', 'a'],
    ['Þ', 'th'], ['þ', 'th'],
    ['Ð', 'd'], ['ð', 'd'],
    ['Ł', 'l'], ['ł', 'l'],
    ['Œ', 'oe'], ['œ', 'oe'],
  ]);

  const cyrillic = {
    А: 'a', а: 'a', Б: 'b', б: 'b', В: 'v', в: 'v', Г: 'g', г: 'g',
    Д: 'd', д: 'd', Е: 'e', е: 'e', Ё: 'e', ё: 'e', Ж: 'zh', ж: 'zh',
    З: 'z', з: 'z', И: 'i', и: 'i', Й: 'i', й: 'i', К: 'k', к: 'k',
    Л: 'l', л: 'l', М: 'm', м: 'm', Н: 'n', н: 'n', О: 'o', о: 'o',
    П: 'p', п: 'p', Р: 'r', р: 'r', С: 's', с: 's', Т: 't', т: 't',
    У: 'u', у: 'u', Ф: 'f', ф: 'f', Х: 'h', х: 'h', Ц: 'ts', ц: 'ts',
    Ч: 'ch', ч: 'ch', Ш: 'sh', ш: 'sh', Щ: 'shch', щ: 'shch',
    Ъ: '', ъ: '', Ы: 'y', ы: 'y', Ь: '', ь: '', Э: 'e', э: 'e',
    Ю: 'yu', ю: 'yu', Я: 'ya', я: 'ya'
  };

  const greek = {
    Α: 'a', α: 'a', Β: 'v', β: 'v', Γ: 'g', γ: 'g', Δ: 'd', δ: 'd',
    Ε: 'e', ε: 'e', Ζ: 'z', ζ: 'z', Η: 'i', η: 'i', Θ: 'th', θ: 'th',
    Ι: 'i', ι: 'i', Κ: 'k', κ: 'k', Λ: 'l', λ: 'l', Μ: 'm', μ: 'm',
    Ν: 'n', ν: 'n', Ξ: 'x', ξ: 'x', Ο: 'o', ο: 'o', Π: 'p', π: 'p',
    Ρ: 'r', ρ: 'r', Σ: 's', σ: 's', ς: 's', Τ: 't', τ: 't', Υ: 'y', υ: 'y',
    Φ: 'f', φ: 'f', Χ: 'ch', χ: 'ch', Ψ: 'ps', ψ: 'ps', Ω: 'o', ω: 'o'
  };

  const value = String(input ?? '').trim();
  if (!value) return '';

  let result = '';
  for (const char of value) {
    if (transliterations.has(char)) {
      result += transliterations.get(char);
    } else if (cyrillic[char]) {
      result += cyrillic[char];
    } else if (greek[char]) {
      result += greek[char];
    } else {
      result += char;
    }
  }

  return result
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/['’]/g, '')
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9\s-]/g, ' ')
    .replace(/[-\s]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

module.exports = { slugify };
