assert.strictEqual(compareVersions('1.10.0', '1.2.9'), 1);
assert.strictEqual(compareVersions('1.2.9', '1.10.0'), -1);
assert.strictEqual(compareVersions('1.0.0', '1'), 0);
assert.strictEqual(compareVersions('1.2', '1.2.0'), 0);
assert.strictEqual(compareVersions('01.002.0003', '1.2.3'), 0);
assert.strictEqual(compareVersions('1.2.3', '1.2.3'), 0);
assert.strictEqual(compareVersions('1.2.3', '1.2.4'), -1);
assert.strictEqual(compareVersions('2', '1.999.999'), 1);
assert.strictEqual(compareVersions('1.0', '1.0.1'), -1);
