function humanFileSize(value) {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    throw new TypeError('bytes must be a finite number');
  }

  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB'];
  const base = 1024;
  const sign = value < 0 ? '-' : '';
  let bytes = Math.abs(value);

  if (bytes === 0) return '0 B';

  let unitIndex = 0;
  while (bytes >= base && unitIndex < units.length - 1) {
    bytes /= base;
    unitIndex++;
  }

  const rounded = bytes >= 10 || Number.isInteger(bytes)
    ? bytes.toFixed(0)
    : bytes.toFixed(1);

  return `${sign}${rounded} ${units[unitIndex]}`;
}
```

