function mergeIntervals(intervals) {
  if (!Array.isArray(intervals)) return [];

  const normalized = [];

  for (const interval of intervals) {
    if (
      !Array.isArray(interval) ||
      interval.length !== 2 ||
      !Number.isFinite(interval[0]) ||
      !Number.isFinite(interval[1])
    ) {
      continue;
    }

    const start = Math.min(interval[0], interval[1]);
    const end = Math.max(interval[0], interval[1]);
    normalized.push([start, end]);
  }

  if (normalized.length === 0) return [];

  normalized.sort((a, b) => a[0] - b[0] || a[1] - b[1]);

  const merged = [normalized[0].slice()];

  for (let i = 1; i < normalized.length; i++) {
    const [start, end] = normalized[i];
    const last = merged[merged.length - 1];

    if (start <= last[1]) {
      last[1] = Math.max(last[1], end);
    } else {
      merged.push([start, end]);
    }
  }

  return merged;
}

module.exports = { mergeIntervals };
```

