    cache.put(2, 'b');
    cache.put(1, 'updated');
    cache.put(3, 'c');
    assert.strictEqual(cache.get(2), -1);
    assert.strictEqual(cache.get(1), 'updated');
    assert.strictEqual(cache.get(3), 'c');
  }

