    assert.strictEqual(cache.get('a'), 1);
    assert.strictEqual(cache.get('a'), 1);
    cache.put('c', 3);
    assert.strictEqual(cache.get('b'), -1);
    assert.strictEqual(cache.get('a'), 1);
    assert.strictEqual(cache.get('c'), 3);
  }

