```js
/**
 * Sort an array of objects by multiple keys and directions.
 *
 * Assumptions:
 * - `rules` is an array of `{ key, direction }` objects.
 * - `direction` may be `'asc'` or `'desc'`; anything else defaults to `'asc'`.
 * - Missing fields (`undefined` or absent keys) sort after defined values in ascending
 *   order and before defined values in descending order.
 * - `null` is treated as a regular value, not as missing.
 * - Values of different JS types are compared with a deterministic fallback:
 *   number < bigint < string < boolean < object < symbol < function < undefined.
 * - If all rule comparisons are equal, original input order is preserved (stable sort),
 *   even on engines where Array.prototype.sort stability is not relied upon.
 */
function sortByMultiple(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }
  if (!Array.isArray(rules)) {
    throw new TypeError('rules must be an array');
  }
  if (items.length <= 1 || rules.length === 0) {
    return items.slice();
  }

  const directionFactor = (direction) => (direction === 'desc' ? -1 : 1);

  const typeRank = (value) => {
    if (value === undefined) return 8;
    const t = typeof value;
    switch (t) {
      case 'number': return 0;
      case 'bigint': return 1;
      case 'string': return 2;
      case 'boolean': return 3;
      case 'object': return 4;
      case 'symbol': return 5;
      case 'function': return 6;
      default: return 7;
    }
  };

  const compareSameType = (a, b) => {
    if (typeof a === 'number') {
      if (Number.isNaN(a) && Number.isNaN(b)) return 0;
      if (Number.isNaN(a)) return 1;
      if (Number.isNaN(b)) return -1;
    }

    if (a instanceof Date && b instanceof Date) {
      return a.getTime() - b.getTime();
    }

    if (typeof a === 'string') {
      return a.localeCompare(b);
    }

    if (typeof a === 'boolean') {
      return Number(a) - Number(b);
    }

    if (typeof a === 'bigint') {
      return a < b ? -1 : a > b ? 1 : 0;
    }

    if (a === b) return 0;
    return String(a).localeCompare(String(b));
  };

  const compareValues = (a, b) => {
    const aMissing = a === undefined;
    const bMissing = b === undefined;

    if (aMissing || bMissing) {
      if (aMissing && bMissing) return 0;
      return aMissing ? 1 : -1;
    }

    const rankDiff = typeRank(a) - typeRank(b);
    if (rankDiff !== 0) return rankDiff;

    return compareSameType(a, b);
  };

  return items
    .map((item, index) => ({ item, index }))
    .sort((left, right) => {
      for (const rule of rules) {
        if (!rule || typeof rule.key !== 'string') continue;
        const factor = directionFactor(rule.direction);
        const result = compareValues(left.item[rule.key], right.item[rule.key]);
        if (result !== 0) return result * factor;
      }
      return left.index - right.index;
    })
    .map((entry) => entry.item);
}

module.exports = { sortByMultiple };
```

