function serializeForm(fields) {
  if (!Array.isArray(fields) || fields.length === 0) return '';

  const parts = [];

  for (const field of fields) {
    const name = field?.name;
    const value = field?.value;

    const encodedName = encodeURIComponent(name == null ? '' : String(name));
    const encodedValue = encodeURIComponent(value == null ? '' : String(value));

    parts.push(`${encodedName}=${encodedValue}`);
  }

  return parts.join('&');
}

module.exports = { serializeForm };
