function nearestPalindrome(n) {
  if (typeof n !== 'string' || !/^[0-9]+$/.test(n) || n.length === 0) {
    throw new TypeError('n must be a non-empty string of digits');
  }

  if (n.length > 1 && n[0] === '0') {
    throw new TypeError('n must not contain leading zeros');
  }

  if (n === '0') {
    throw new TypeError('n must be a positive integer string');
  }

  const original = BigInt(n);
  const len = n.length;
  const halfLen = Math.ceil(len / 2);
  const prefix = n.slice(0, halfLen);

  function makePalindrome(prefixStr, targetLen) {
    const left = prefixStr;
    const right = left
      .slice(0, targetLen % 2 === 0 ? left.length : left.length - 1)
      .split('')
      .reverse()
      .join('');
    return (left + right).replace(/^0+(?=\d)/, '') || '0';
  }

  const candidates = new Set();

  candidates.add('9'.repeat(len - 1) || '0');
  candidates.add('1' + '0'.repeat(len - 1) + '1');

  for (const delta of [-1n, 0n, 1n]) {
    const adjusted = (BigInt(prefix) + delta).toString();
    candidates.add(makePalindrome(adjusted, len));
  }

  candidates.delete(n);

  let best = null;
  let bestDiff = null;

  for (const candidate of candidates) {
    if (!/^[0-9]+$/.test(candidate)) continue;
    const value = BigInt(candidate);
    if (value <= 0n) continue;

    const diff = value > original ? value - original : original - value;

    if (
      best === null ||
      diff < bestDiff ||
      (diff === bestDiff && value < BigInt(best))
    ) {
      best = candidate;
      bestDiff = diff;
    }
  }

  return best;
}

