function runTests() {
  const cases = [
    ['1', '2', '1'],
    ['9', '8', 'single digit tie picks smaller'],
    ['10', '9', 'power of ten'],
    ['1000', '999', 'power of ten larger'],
    ['11', '9', 'already palindromic'],
    ['121', '111', 'palindromic tie picks smaller'],
    ['123', '121', 'normal case'],
    ['1283', '1331', 'closest larger palindrome'],
    ['99', '101', 'all nines'],
    ['1001', '999', 'palindrome near lower boundary'],
    ['123456789876543210', '123456789987654321', 'very large input'],
  ];

  for (const [input, expected, label] of cases) {
