function removeComments(code) {
  let result = '';
  let i = 0;
  let state = 'code';
  let stringQuote = '';

  while (i < code.length) {
    const ch = code[i];
    const next = code[i + 1];

    if (state === 'code') {
      if (ch === '"' || ch === "'" || ch === '`') {
        state = 'string';
        stringQuote = ch;
        result += ch;
        i += 1;
        continue;
      }

      if (ch === '/' && next === '/') {
        i += 2;
        while (i < code.length && code[i] !== '\n') {
          i += 1;
        }
        continue;
      }

      if (ch === '/' && next === '*') {
        i += 2;
        while (i < code.length && !(code[i] === '*' && code[i + 1] === '/')) {
          i += 1;
        }
        if (i < code.length) {
          i += 2;
        } else {
          break;
        }
        continue;
      }

      result += ch;
      i += 1;
      continue;
    }

    if (state === 'string') {
      result += ch;

      if (ch === '\\') {
        if (i + 1 < code.length) {
          result += code[i + 1];
          i += 2;
          continue;
        }
        i += 1;
        continue;
      }

      if (ch === stringQuote) {
        state = 'code';
        stringQuote = '';
      }

      i += 1;
    }
  }

  return result;
}

