function findPeakElement(nums) {
  if (!Array.isArray(nums) || nums.length === 0) return -1;
  if (nums.length === 1) return 0;

  for (let i = 0; i < nums.length; i++) {
    const left = i === 0 ? -Infinity : nums[i - 1];
    const right = i === nums.length - 1 ? -Infinity : nums[i + 1];

    // A peak is any element not smaller than its neighbors.
    // This treats ties as valid peaks, so plateau values can qualify.
    if (nums[i] >= left && nums[i] >= right) {
      return i;
    }
  }

  return -1;
}

module.exports = { findPeakElement };
```

