function romanToInt(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Roman numeral must be a string');
  }

  const s = input.trim();
  if (s.length === 0) {
    throw new Error('Roman numeral cannot be empty');
  }
  if (!/^[ivxlcdm]+$/i.test(s)) {
    throw new Error('Roman numeral contains invalid characters');
  }

  const roman = s.toUpperCase();
  const values = {
    I: 1,
    V: 5,
    X: 10,
    L: 50,
    C: 100,
    D: 500,
    M: 1000,
  };
  const maxRepeats = {
    I: 3,
    X: 3,
    C: 3,
    M: 3,
    V: 1,
    L: 1,
    D: 1,
  };
  const subtractives = new Set(['IV', 'IX', 'XL', 'XC', 'CD', 'CM']);

  let total = 0;
  let i = 0;
  let repeatCount = 1;

  while (i < roman.length) {
    const current = roman[i];
    const currentValue = values[current];
    const next = roman[i + 1];
    const nextValue = next ? values[next] : 0;

    if (i > 0 && roman[i - 1] === current) {
      repeatCount += 1;
    } else {
      repeatCount = 1;
    }

    if (repeatCount > maxRepeats[current]) {
      throw new Error(`Invalid repetition: ${current}`);
    }

    if (nextValue > currentValue) {
      const pair = current + next;

      if (!subtractives.has(pair)) {
        throw new Error(`Invalid subtractive pattern: ${pair}`);
      }
      if (repeatCount > 1) {
        throw new Error(`Invalid repetition before subtractive pattern: ${pair}`);
      }
      if (i >= 2 && roman[i - 1] === current) {
        throw new Error(`Malformed numeral near: ${pair}`);
      }

      total += nextValue - currentValue;
      i += 2;
      repeatCount = 1;
      continue;
    }

    total += currentValue;
    i += 1;
  }

  const intToRoman = (num) => {
    const table = [
      ['M', 1000],
      ['CM', 900],
      ['D', 500],
      ['CD', 400],
      ['C', 100],
      ['XC', 90],
      ['L', 50],
      ['XL', 40],
      ['X', 10],
      ['IX', 9],
      ['V', 5],
      ['IV', 4],
      ['I', 1],
    ];

    let result = '';
    for (const [symbol, value] of table) {
      while (num >= value) {
        result += symbol;
        num -= value;
      }
    }
    return result;
  };

  if (intToRoman(total) !== roman) {
    throw new Error('Malformed Roman numeral');
  }

  return total;
}

