571.answer:
A **prefix sum** array stores cumulative totals so you can get any subarray sum with one subtraction.

If `arr = [a0, a1, a2, ...]`, define:
- `prefix[0] = 0`
- `prefix[i + 1] = prefix[i] + arr[i]`

So `prefix[k]` is the sum of the first `k` elements.

Then the sum of `arr[left..right]` is:

```text
prefix[right + 1] - prefix[left]
```

Why it works:
- `prefix[right + 1]` includes everything up to `right`
- `prefix[left]` includes everything before `left`
- subtracting removes the unwanted part

That gives:
- **Preprocessing:** `O(n)`
- **Each query:** `O(1)`
- **Extra space:** `O(n)`

### Example

```text
arr = [2, 4, 1, 7, 3]
prefix = [0, 2, 6, 7, 14, 17]
```

Sum from index `1` to `3`:

```text
prefix[4] - prefix[1] = 14 - 2 = 12
```

And indeed:

```text
4 + 1 + 7 = 12
```

### JavaScript implementation

```js
function buildRangeSumQuery(arr) {
  const prefix = new Array(arr.length + 1).fill(0);

  for (let i = 0; i < arr.length; i++) {
    prefix[i + 1] = prefix[i] + arr[i];
  }

  return function rangeSum(left, right) {
    if (left < 0 || right >= arr.length || left > right) {
      throw new Error("Invalid query range");
    }
    return prefix[right + 1] - prefix[left];
  };
}
```

### Usage

```js
const arr = [2, 4, 1, 7, 3];
const rangeSum = buildRangeSumQuery(arr);

console.log(rangeSum(1, 3)); // 12
console.log(rangeSum(0, 4)); // 17
console.log(rangeSum(2, 2)); // 1
```

### If you want all query answers at once

```js
function answerRangeSumQueries(arr, queries) {
  const prefix = new Array(arr.length + 1).fill(0);

  for (let i = 0; i < arr.length; i++) {
    prefix[i + 1] = prefix[i] + arr[i];
  }

  return queries.map(([left, right]) => {
    if (left < 0 || right >= arr.length || left > right) {
      throw new Error(`Invalid query range: [${left}, ${right}]`);
    }
    return prefix[right + 1] - prefix[left];
  });
}
```

```js
console.log(answerRangeSumQueries([2, 4, 1, 7, 3], [[1, 3], [0, 4], [2, 2]]));
// [12, 17, 1]
```

