Markdown headings use 1-6 leading `#` characters: `#` for H1, `##` for H2, through `######` for H6. A heading nests under the nearest previous heading with a smaller level, so an H3 belongs inside the most recent H2, and a new H2 starts a sibling section.

```js
function parseMarkdownToc(markdown) {
  const lines = markdown.split(/\r?\n/);
  const toc = [];
  const stack = [];

  for (const line of lines) {
    const match = /^(#{1,6})\s+(.+?)\s*$/.exec(line);
    if (!match) continue;

    const level = match[1].length;
    const title = match[2].replace(/\s+#+\s*$/, '').trim();
    const node = { title, level, children: [] };

    while (stack.length && stack[stack.length - 1].level >= level) {
      stack.pop();
    }

    if (stack.length === 0) {
      toc.push(node);
    } else {
      stack[stack.length - 1].children.push(node);
    }

    stack.push(node);
  }

  return toc;
}
```

Example:

```js
const md = `# Intro
## Getting Started
### Install
## Usage
# API`;

console.log(JSON.stringify(parseMarkdownToc(md), null, 2));
```

Result:

```json
[
  {
    "title": "Intro",
    "level": 1,
    "children": [
      {
        "title": "Getting Started",
        "level": 2,
        "children": [
          {
            "title": "Install",
            "level": 3,
            "children": []
          }
        ]
      },
      {
        "title": "Usage",
        "level": 2,
