```python
from typing import Any, Callable, Dict, Iterable, List, Optional, Tuple


def process_records(
    records: Iterable[Dict[str, Any]],
    save_fn: Callable[[Dict[str, Any]], Any],
    report_fn: Callable[[List[Dict[str, Any]], List[Dict[str, Any]]], None],
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
    valid_records = []
    invalid_records = []

    for record in records:
        normalized = normalize_record(record)
        validation_error = validate_record(normalized)

        if validation_error is not None:
            invalid_records.append({"record": normalized, "error": validation_error})
            continue

        persisted = persist_record(normalized, save_fn)
        valid_records.append(persisted)

    report_results(valid_records, invalid_records, report_fn)
    return valid_records, invalid_records


def normalize_record(record: Dict[str, Any]) -> Dict[str, Any]:
    normalized = dict(record)

    if "email" in normalized and isinstance(normalized["email"], str):
        normalized["email"] = normalized["email"].strip().lower()

    if "name" in normalized and isinstance(normalized["name"], str):
        normalized["name"] = normalized["name"].strip()

    return normalized


def validate_record(record: Dict[str, Any]) -> Optional[str]:
    if not record.get("email"):
        return "Missing email"

    if "@" not in record["email"]:
        return "Invalid email"

    return None


def persist_record(
    record: Dict[str, Any],
    save_fn: Callable[[Dict[str, Any]], Any],
) -> Dict[str, Any]:
    save_fn(record)
    return record


def report_results(
    valid_records: List[Dict[str, Any]],
    invalid_records: List[Dict[str, Any]],
    report_fn: Callable[[List[Dict[str, Any]], List[Dict[str, Any]]], None],
) -> None:
    report_fn(valid_records, invalid_records)
```

