import fs from "node:fs/promises";

const BASE_URL = "https://api.example.com/v1/users";

async function fetchAllUsers() {
  const users = [];
  const seenIds = new Set();

  for (let page = 1; ; page++) {
    const res = await fetch(`${BASE_URL}?page=${page}`);
    if (!res.ok) {
      throw new Error(`Request failed for page ${page}: ${res.status} ${res.statusText}`);
    }

    const body = await res.json();
    const data = body.data;

    if (!Array.isArray(data)) {
      throw new Error(`Invalid response for page ${page}: expected data array`);
    }

    if (data.length === 0) {
      break;
    }

    for (const user of data) {
      if (seenIds.has(user.id)) {
        throw new Error(`Duplicate id found across pages: ${user.id}`);
      }
      seenIds.add(user.id);

      users.push({
        id: user.id,
        name: user.full_name,
        created_at: user.created_at,
      });
    }
  }

  return users;
}

function toCsv(rows) {
  const headers = ["id", "name", "created_at"];

  const escape = (value) => {
    const str = String(value ?? "");
    return /[",\n]/.test(str) ? `"${str.replace(/"/g, '""')}"` : str;
  };

  return [
    headers.join(","),
    ...rows.map((row) => headers.map((h) => escape(row[h])).join(",")),
  ].join("\n");
}

async function main() {
  const users = await fetchAllUsers();
  const csv = toCsv(users);
  await fs.writeFile("users.csv", csv + "\n", "utf8");
  console.log(`Wrote ${users.length} users to users.csv`);
}

main().catch((err) => {
  console.error(err.message);
  process.exit(1);
});
