Prim’s algorithm grows a minimum spanning tree (MST) one vertex at a time by always choosing the smallest-weight edge that connects a vertex already in the tree to a vertex outside it.

### How it works
1. Start from any node.
2. Mark it as part of the MST.
3. Push all outgoing edges into a min-priority queue.
4. Repeatedly pop the smallest edge:
   - If it leads to a node already in the MST, skip it.
   - Otherwise, add that node to the MST, add the edge weight to the total, and push that node’s outgoing edges.
5. Stop when all vertices are included.

### Why it works
At each step, Prim’s picks the cheapest edge crossing the cut between the built tree and the remaining graph. By the cut property, that edge is always safe to include in some MST.

### Complexity
With an adjacency list and binary heap priority queue:
- **Time:** `O((V + E) log V)` (often written `O(E log V)`)
- **Space:** `O(V + E)`

### Go implementation
```go
package main

import (
	"container/heap"
	"fmt"
)

type Edge struct {
	to     int
	weight int
}

type Item struct {
	node   int
	weight int
}

type MinHeap []Item

func (h MinHeap) Len() int            { return len(h) }
func (h MinHeap) Less(i, j int) bool  { return h[i].weight < h[j].weight }
func (h MinHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x any)         { *h = append(*h, x.(Item)) }
func (h *MinHeap) Pop() any {
	old := *h
	n := len(old)
	item := old[n-1]
	*h = old[:n-1]
	return item
}

// primMST returns the total weight of the minimum spanning tree.
// n is the number of vertices labeled 0..n-1.
func primMST(n int, graph [][]Edge) int {
	if n == 0 {
		return 0
	}

	visited := make([]bool, n)
	pq := &MinHeap{}
	heap.Init(pq)

	totalWeight := 0
	visitedCount := 0

	// Start from node 0 with cost 0.
	heap.Push(pq, Item{node: 0, weight: 0})

	for pq.Len() > 0 && visitedCount < n {
		item := heap.Pop(pq).(Item)
		u := item.node

		if visited[u] {
			continue
		}

		visited[u] = true
		visitedCount++
		totalWeight += item.weight

		for _, edge := range graph[u] {
			if !visited[edge.to] {
				heap.Push(pq, Item{node: edge.to, weight: edge.weight})
			}
		}
	}

	return totalWeight
}

func main() {
	n := 5
	graph := make([][]Edge, n)

	addEdge := func(u, v, w int) {
		graph[u] = append(graph[u], Edge{to: v, weight: w})
		graph[v] = append(graph[v], Edge{to: u, weight: w})
	}

	addEdge(0, 1, 2)
	addEdge(0, 3, 6)
	addEdge(1, 2, 3)
	addEdge(1, 3, 8)
	addEdge(1, 4, 5)
	addEdge(2, 4, 7)
	addEdge(3, 4, 9)

	fmt.Println(primMST(n, graph)) // 16
}
```

### Note
This assumes the graph is connected. If it may be disconnected, detect that with `visitedCount != n` and return an error or compute a minimum spanning forest instead.

