The Template Method pattern defines the skeleton of an algorithm in a base class and lets subclasses override specific steps without changing the overall flow.

### When to use it
- Multiple classes follow the same high-level process
- Some steps vary by type
- You want to enforce order while allowing customization

### Structure
- **Template method**: the fixed algorithm in the base class
- **Primitive operations**: abstract/virtual methods subclasses implement
- **Hooks**: optional overridable steps

For a data parser, the flow can be:
1. Load raw input
2. Validate input
3. Parse records
4. Post-process results
5. Return parsed data

The base class owns that sequence, while CSV and JSON parsers implement the format-specific parts.

## C# example
```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.Json;

public abstract class DataParser
{
    // Template method
    public List<Dictionary<string, string>> Parse(string input)
    {
        string raw = Load(input);
        Validate(raw);
        List<Dictionary<string, string>> records = ParseRecords(raw);
        PostProcess(records);
        return records;
    }

    protected virtual string Load(string input)
    {
        return input?.Trim() ?? string.Empty;
    }

    protected virtual void Validate(string raw)
    {
        if (string.IsNullOrWhiteSpace(raw))
            throw new ArgumentException("Input cannot be empty.");
    }

    protected abstract List<Dictionary<string, string>> ParseRecords(string raw);

    protected virtual void PostProcess(List<Dictionary<string, string>> records)
    {
        // Optional hook for subclasses
    }
}

public class CsvParser : DataParser
{
    protected override List<Dictionary<string, string>> ParseRecords(string raw)
    {
        var lines = raw.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
        if (lines.Length < 2)
            throw new FormatException("CSV must contain a header and at least one data row.");

        string[] headers = lines[0].Split(',').Select(h => h.Trim()).ToArray();
        var result = new List<Dictionary<string, string>>();

        for (int i = 1; i < lines.Length; i++)
        {
            string[] values = lines[i].Split(',').Select(v => v.Trim()).ToArray();
            if (values.Length != headers.Length)
                throw new FormatException($"Row {i} has {values.Length} values, expected {headers.Length}.");

            var record = new Dictionary<string, string>();
            for (int j = 0; j < headers.Length; j++)
                record[headers[j]] = values[j];

            result.Add(record);
        }

        return result;
    }

    protected override void PostProcess(List<Dictionary<string, string>> records)
    {
        foreach (var record in records)
        {
            foreach (var key in record.Keys.ToList())
                record[key] = record[key].Trim();
        }
    }
}

public class JsonParser : DataParser
{
    protected override List<Dictionary<string, string>> ParseRecords(string raw)
    {
        using JsonDocument doc = JsonDocument.Parse(raw);

        if (doc.RootElement.ValueKind != JsonValueKind.Array)
            throw new FormatException("JSON input must be an array of objects.");

        var result = new List<Dictionary<string, string>>();

        foreach (JsonElement item in doc.RootElement.EnumerateArray())
        {
            if (item.ValueKind != JsonValueKind.Object)
                throw new FormatException("Each JSON array item must be an object.");

            var record = new Dictionary<string, string>();
            foreach (JsonProperty property in item.EnumerateObject())
                record[property.Name] = property.Value.ToString();

            result.Add(record);
        }

        return result;
    }

    protected override void Validate(string raw)
    {
        base.Validate(raw);

        if (!raw.TrimStart().StartsWith("["))
            throw new FormatException("JSON parser expects a JSON array.");
    }
}

public static class Demo
{
    public static void Main()
    {
        string csv = @"
name,age,city
Alice,30,Paris
Bob,25,London";

        string json = @"[
  { ""name"": ""Alice"", ""age"": 30, ""city"": ""Paris"" },
  { ""name"": ""Bob"", ""age"": 25, ""city"": ""London"" }
]";

        DataParser csvParser = new CsvParser();
        DataParser jsonParser = new JsonParser();

        Print("CSV", csvParser.Parse(csv));
        Print("JSON", jsonParser.Parse(json));
    }

    private static void Print(string label, List<Dictionary<string, string>> records)
    {
        Console.WriteLine($"--- {label} ---");
        foreach (var record in records)
        {
            Console.WriteLine(string.Join(", ", record.Select(kv => $"{kv.Key}={kv.Value}")));
        }
    }
}
```

### Why this is Template Method
- `DataParser.Parse()` is the template method
- `Load()`, `Validate()`, `ParseRecords()`, and `PostProcess()` are the steps
- `ParseRecords()` is required for subclasses
- `Validate()` and `PostProcess()` are hooks subclasses can override

### Benefits
- Reuses the common workflow
- Prevents duplicated control flow
- Makes format-specific behavior easy to extend

If you want, I can also provide a version using strongly typed `Record` objects instead of `Dictionary<string, string>`.

