The repository pattern abstracts data access behind a small interface so the rest of the application works with domain objects instead of storage details. It gives you a single place to handle persistence concerns, makes business logic easier to test, and lets you swap implementations later, like in-memory for tests and SQL for production.

A typical repository exposes collection-like operations such as add, get by id, and list all, while hiding how objects are stored.

```python
from __future__ import annotations

from dataclasses import dataclass
from typing import Dict, Generic, List, Optional, Protocol, TypeVar


@dataclass(frozen=True)
class User:
    id: int
    name: str


T = TypeVar("T")
ID = TypeVar("ID")


class Repository(Protocol[T, ID]):
    def add(self, entity: T) -> None:
        ...

    def get_by_id(self, entity_id: ID) -> Optional[T]:
        ...

    def list_all(self) -> List[T]:
        ...


class InMemoryRepository(Generic[T, ID]):
    def __init__(self) -> None:
        self._items: Dict[ID, T] = {}

    def add(self, entity: T) -> None:
        entity_id = getattr(entity, "id")
        self._items[entity_id] = entity

    def get_by_id(self, entity_id: ID) -> Optional[T]:
        return self._items.get(entity_id)

    def list_all(self) -> List[T]:
        return list(self._items.values())


if __name__ == "__main__":
    repo = InMemoryRepository[User, int]()

    repo.add(User(id=1, name="Alice"))
    repo.add(User(id=2, name="Bob"))

    print(repo.get_by_id(1))
    print(repo.list_all())
```

Example output:

```python
User(id=1, name='Alice')
[User(id=1, name='Alice'), User(id=2, name='Bob')]
```

