Middleware chaining passes a request through a sequence of functions, where each middleware can inspect or modify the request/response, stop the flow, or delegate to the next middleware by calling `next()`. This keeps concerns like logging, auth, and routing separate and composable.

```js
function compose(middlewares) {
  return function run(req, res) {
    let index = -1;

    function dispatch(i) {
      if (i <= index) {
        throw new Error('next() called multiple times');
      }
      index = i;

      const middleware = middlewares[i];
      if (!middleware) return;

      return middleware(req, res, () => dispatch(i + 1));
    }

    return dispatch(0);
  };
}

function logger(req, res, next) {
  console.log(`[LOG] ${req.method} ${req.url}`);
  next();
}

function authenticate(req, res, next) {
  if (req.headers.authorization !== 'Bearer secret-token') {
    res.statusCode = 401;
    res.body = { error: 'Unauthorized' };
    return;
  }

  req.user = { id: 1, role: 'admin' };
  next();
}

function handler(req, res, next) {
  res.statusCode = 200;
  res.body = {
    message: 'Success',
    user: req.user,
  };
  next?.();
}

const app = compose([logger, authenticate, handler]);

const okReq = {
  method: 'GET',
  url: '/profile',
  headers: { authorization: 'Bearer secret-token' },
};
const okRes = {};
app(okReq, okRes);
console.log(okRes);
// { statusCode: 200, body: { message: 'Success', user: { id: 1, role: 'admin' } } }

const badReq = {
  method: 'GET',
  url: '/profile',
  headers: {},
};
const badRes = {};
app(badReq, badRes);
console.log(badRes);
// { statusCode: 401, body: { error: 'Unauthorized' } }
```

Behavior:
- `logger` always runs first.
- `authenticate` either rejects the request or adds `req.user` and continues.
- `handler` produces the final response.
- If a middleware does not call `next()`, the chain stops there.

