```js
function canonicalUsername(input) {
  return input
    .normalize('NFKC')
    .toLocaleLowerCase('en-US');
}

function validateUsername(username, existingUsernames = []) {
  const canonical = canonicalUsername(username);

  if (!canonical) {
    return { ok: false, reason: 'Username is required.' };
  }

  for (const existing of existingUsernames) {
    if (canonicalUsername(existing) === canonical) {
      return {
        ok: false,
        reason: `Username collides with existing identifier: ${existing}`,
        canonical,
      };
    }
  }

  return { ok: true, canonical };
}

