type QueryValueState =
  | { kind: 'missing' }
  | { kind: 'empty' }
  | { kind: 'null'; raw: string }
  | { kind: 'value'; value: string };

const NULL_LIKE_VALUES = new Set(['null', 'undefined', 'nil']);

export function parseOptionalQueryParam(
  params: URLSearchParams,
  key: string,
): QueryValueState {
  if (!params.has(key)) {
    return { kind: 'missing' };
  }

  const raw = params.get(key);

  if (raw === null) {
    return { kind: 'missing' };
  }

  if (raw === '') {
    return { kind: 'empty' };
  }

  if (NULL_LIKE_VALUES.has(raw.trim().toLowerCase())) {
    return { kind: 'null', raw };
  }

  return { kind: 'value', value: raw };
}

// Example usage
const examples = [
  '',
  '?q=',
  '?q=null',
  '?q=hello',
];

for (const query of examples) {
  const params = new URLSearchParams(query);
  console.log(query || '(no query)', parseOptionalQueryParam(params, 'q'));
}
```

Behavior:
- no `q` at all → `{ kind: 'missing' }`
- `?q=` → `{ kind: 'empty' }`
- `?q=null` / `?q=undefined` / `?q=nil` → `{ kind: 'null', raw: ... }`
- `?q=hello` → `{ kind: 'value', value: 'hello' }`

