```js
function deepClone(value, seen = new Map()) {
  if (value === null || typeof value !== 'object') return value;

  if (seen.has(value)) return seen.get(value);

  if (value instanceof Date) {
    const clone = new Date(value.getTime());
    seen.set(value, clone);
    return clone;
  }

  if (value instanceof RegExp) {
    const clone = new RegExp(value.source, value.flags);
    clone.lastIndex = value.lastIndex;
    seen.set(value, clone);
    return clone;
  }

  if (value instanceof Map) {
    const clone = new Map();
    seen.set(value, clone);
    for (const [key, entryValue] of value) {
      clone.set(deepClone(key, seen), deepClone(entryValue, seen));
    }
    return clone;
  }

  if (value instanceof Set) {
    const clone = new Set();
    seen.set(value, clone);
    for (const entry of value) {
      clone.add(deepClone(entry, seen));
    }
    return clone;
  }

  if (Array.isArray(value)) {
    const clone = [];
    seen.set(value, clone);
    for (const item of value) {
      clone.push(deepClone(item, seen));
    }
    return clone;
  }

  const clone = Object.create(Object.getPrototypeOf(value));
  seen.set(value, clone);

  for (const key of Reflect.ownKeys(value)) {
    const descriptor = Object.getOwnPropertyDescriptor(value, key);
    if (!descriptor) continue;

    if ('value' in descriptor) {
      descriptor.value = deepClone(descriptor.value, seen);
    }

    Object.defineProperty(clone, key, descriptor);
  }

  return clone;
}
```

Preserves:
- nested objects and arrays
- `Date`, `Map`, `Set`, `RegExp`
- circular references
- shared references/identity within the cloned graph
- property descriptors and symbol keys

Example:
```js
const shared = { x: 1 };
const original = {
  a: shared,
  b: shared,
  d: new Date(),
  m: new Map([[shared, new Set([shared])]]),
};
original.self = original;

const cloned = deepClone(original);

console.log(cloned !== original); // true
console.log(cloned.a === cloned.b); // true
console.log(cloned.self === cloned); // true
console.log(cloned.m instanceof Map); // true
```

