      if (!(left instanceof Map && right instanceof Map)) return false;
      if (left.size !== right.size) return false;

      const unmatched = Array.from(right.entries());
      outerMap: for (const [lk, lv] of left) {
        for (let i = 0; i < unmatched.length; i++) {
          const [rk, rv] = unmatched[i];
          if (deepStructuralEqual(lk, rk) && deepStructuralEqual(lv, rv)) {
            unmatched.splice(i, 1);
            continue outerMap;
