      if (!rightKeys.includes(key)) return false;
    }

    for (const key of leftKeys) {
      const leftDesc = Object.getOwnPropertyDescriptor(left, key);
      const rightDesc = Object.getOwnPropertyDescriptor(right, key);
      if (!rightDesc) return false;

      if (leftDesc.enumerable !== rightDesc.enumerable ||
          leftDesc.configurable !== rightDesc.configurable) {
        return false;
