      const leftIsData = 'value' in leftDesc;
      const rightIsData = 'value' in rightDesc;
      if (leftIsData !== rightIsData) return false;

      if (leftIsData) {
        if (leftDesc.writable !== rightDesc.writable) return false;
        stack.push({ a: leftDesc.value, b: rightDesc.value });
      } else {
        if (!Object.is(leftDesc.get, rightDesc.get) || !Object.is(leftDesc.set, rightDesc.set)) {
          return false;
        }
      }
