function flattenObject(input) {
  const out = {};

  const escapeSegment = (segment) =>
    String(segment)
      .replace(/\\/g, "\\\\")
      .replace(/\./g, "\\.");

  const joinPath = (parts) => parts.map(escapeSegment).join(".");

  const walk = (value, path) => {
    if (Array.isArray(value)) {
      if (value.length === 0) {
        out[joinPath(path)] = [];
        return;
      }

      value.forEach((item, index) => {
        walk(item, [...path, String(index)]);
      });
      return;
    }

    if (value && typeof value === "object") {
      const entries = Object.entries(value);
      if (entries.length === 0) {
        out[joinPath(path)] = {};
        return;
      }

      for (const [key, child] of entries) {
        walk(child, [...path, key]);
      }
      return;
    }

    out[joinPath(path)] = value;
  };

  for (const [key, value] of Object.entries(input)) {
    walk(value, [key]);
  }

  return out;
}
```

Escaping strategy:
- Path separator is a literal `.`.
- Inside an original key segment, `.` is escaped as `\.`.
- `\\` is escaped as `\\\\` first, so escaping is reversible.
- Array indexes are emitted as normal path segments (`items.0.name`).
- Empty objects and empty arrays are preserved as values at their path.

Example:

