    emptyObj: {},
    emptyArr: [],
  },
  list: [{ "x.y": 2 }],
};

console.log(flattenObject(input));
// {
//   'a\\.b.c': 1,
//   'a\\.b.emptyObj': {},
//   'a\\.b.emptyArr': [],
//   'list.0.x\\.y': 2
// }
```

