```js
function decimalToBinary(decimal) {
  if (!/^[0-9]+$/.test(decimal)) throw new Error('Invalid decimal string');
  if (decimal === '0') return '0';

  let digits = decimal;
  const bits = [];

  while (digits !== '0') {
    let quotient = '';
    let carry = 0;

    for (let i = 0; i < digits.length; i++) {
      const value = carry * 10 + (digits.charCodeAt(i) - 48);
      const q = Math.floor(value / 2);
      carry = value % 2;
      if (quotient.length > 0 || q !== 0) quotient += q;
    }

    bits.push(carry);
    digits = quotient.length === 0 ? '0' : quotient;
  }

  return bits.reverse().join('');
}

// Example
console.log(decimalToBinary('13')); // 1101
console.log(decimalToBinary('123456789012345678901234567890'));
```

This uses repeated long division on the decimal string, so it preserves exact precision for inputs with 100,000 digits. Time complexity is roughly O(d²), where d is the number of decimal digits, and space is O(d).

