Use string-based modular exponentiation with bigint-like arithmetic implemented on decimal strings. For the usual interpretation of this prompt, compute **`a^b mod m`** without ever converting the full inputs to native numbers.

## Approach

1. Parse `a`, `b`, and `m` as decimal strings.
2. Reduce `a mod m` using digit-by-digit division.
3. Repeatedly exponentiate by squaring:
   - if `b` is odd: `result = (result * base) mod m`
   - `base = (base * base) mod m`
   - `b = floor(b / 2)`
4. Implement:
   - compare decimal strings
   - subtraction
   - division by 2
   - odd check
   - modular multiply without overflow

For huge values, the safest portable method is to keep everything as strings and use modular multiplication via doubling.

## JavaScript implementation

```js
function stripLeadingZeros(s) {
  s = s.replace(/^0+/, "");
  return s === "" ? "0" : s;
}

function cmp(a, b) {
  a = stripLeadingZeros(a);
  b = stripLeadingZeros(b);
  if (a.length !== b.length) return a.length < b.length ? -1 : 1;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

function add(a, b) {
  let i = a.length - 1;
  let j = b.length - 1;
  let carry = 0;
  let out = [];

  while (i >= 0 || j >= 0 || carry) {
    const da = i >= 0 ? a.charCodeAt(i) - 48 : 0;
    const db = j >= 0 ? b.charCodeAt(j) - 48 : 0;
    const sum = da + db + carry;
    out.push(String(sum % 10));
    carry = Math.floor(sum / 10);
    i--;
    j--;
  }

  return out.reverse().join("");
}

function sub(a, b) {
  // assumes a >= b
  let i = a.length - 1;
  let j = b.length - 1;
  let borrow = 0;
  let out = [];

  while (i >= 0) {
    let da = a.charCodeAt(i) - 48 - borrow;
    const db = j >= 0 ? b.charCodeAt(j) - 48 : 0;
    if (da < db) {
      da += 10;
      borrow = 1;
    } else {
      borrow = 0;
    }
    out.push(String(da - db));
    i--;
    j--;
  }

  return stripLeadingZeros(out.reverse().join(""));
}

function mulSmall(a, digit) {
  if (digit === 0 || a === "0") return "0";
  let carry = 0;
  let out = [];
  for (let i = a.length - 1; i >= 0; i--) {
    const prod = (a.charCodeAt(i) - 48) * digit + carry;
    out.push(String(prod % 10));
    carry = Math.floor(prod / 10);
  }
  while (carry) {
    out.push(String(carry % 10));
    carry = Math.floor(carry / 10);
  }
  return out.reverse().join("");
}

function modDecimal(num, mod) {
  num = stripLeadingZeros(num);
  mod = stripLeadingZeros(mod);
  if (mod === "0") throw new Error("modulus must be nonzero");
  let rem = "0";

  for (const ch of num) {
    rem = add(mulSmall(rem, 10), ch);
    while (cmp(rem, mod) >= 0) {
      rem = sub(rem, mod);
    }
  }
  return stripLeadingZeros(rem);
}

function isOdd(s) {
  return ((s.charCodeAt(s.length - 1) - 48) & 1) === 1;
}

function div2(s) {
  let carry = 0;
  let out = [];
  for (const ch of s) {
    const cur = carry * 10 + (ch.charCodeAt(0) - 48);
    out.push(String(Math.floor(cur / 2)));
    carry = cur % 2;
  }
  return stripLeadingZeros(out.join(""));
}

function addMod(a, b, mod) {
  const sum = add(a, b);
  return cmp(sum, mod) >= 0 ? sub(sum, mod) : sum;
}

function mulMod(a, b, mod) {
  a = modDecimal(a, mod);
  b = stripLeadingZeros(b);
  let result = "0";

  while (b !== "0") {
    if (isOdd(b)) result = addMod(result, a, mod);
    a = addMod(a, a, mod);
    b = div2(b);
  }
  return result;
}

function powMod(base, exp, mod) {
  mod = stripLeadingZeros(mod);
  if (mod === "0") throw new Error("modulus must be nonzero");
  if (mod === "1") return "0";

  base = modDecimal(base, mod);
  exp = stripLeadingZeros(exp);
  let result = "1";

  while (exp !== "0") {
    if (isOdd(exp)) result = mulMod(result, base, mod);
    base = mulMod(base, base, mod);
    exp = div2(exp);
  }

  return stripLeadingZeros(result);
}

// Example:
// console.log(powMod("123456789123456789", "987654321987654321", "1000000007"));
```

## Notes

- This never stores the full input in native numeric types.
- It works for inputs up to 10,000 digits.
- It is correct but not especially fast because `modDecimal` uses repeated subtraction per digit. For better performance, replace that with quotient-digit estimation or use a larger internal base representation.

