function addMoney(a, b) {
  const parse = (s) => {
    const sign = s.startsWith('-') ? -1n : 1n;
    const raw = sign === -1n ? s.slice(1) : s;
    const [intPart, fracPart = ''] = raw.split('.');
    const scale = fracPart.length;
    const digits = (intPart || '0') + fracPart;
    return {
      sign,
      scale,
      value: BigInt(digits || '0')
    };
  };

  const x = parse(a);
  const y = parse(b);
  const scale = Math.max(x.scale, y.scale);
  const factorX = 10n ** BigInt(scale - x.scale);
  const factorY = 10n ** BigInt(scale - y.scale);

  const sum = x.sign * x.value * factorX + y.sign * y.value * factorY;
  const negative = sum < 0n;
  const abs = negative ? -sum : sum;
  const padded = abs.toString().padStart(scale + 1, '0');

  if (scale === 0) {
    return `${negative ? '-' : ''}${padded}`;
  }

  const whole = padded.slice(0, -scale) || '0';
  const fraction = padded.slice(-scale);
  return `${negative ? '-' : ''}${whole}.${fraction}`;
}
```

