Use IEEE 754 round-half-to-even on decimal strings. Example expectations for 1 decimal place: `0.05 -> 0.0`, `0.15 -> 0.2`, `0.25 -> 0.2`, `0.35 -> 0.4`; and for 0 places: `2.5 -> 2`, `3.5 -> 4`, `-2.5 -> -2`, `-3.5 -> -4`.

```js
function roundDecimalStringBankers(input, places) {
  const s = String(input).trim();
  if (!/^[-+]?\d+(?:\.\d+)?$/.test(s)) throw new Error('Invalid decimal string');
  if (!Number.isInteger(places) || places < 0) throw new Error('Invalid places');

  let sign = '';
  let body = s;
  if (body[0] === '+' || body[0] === '-') {
    sign = body[0] === '-' ? '-' : '';
    body = body.slice(1);
  }

  let [intPart, fracPart = ''] = body.split('.');
  fracPart = fracPart.replace(/\D/g, '');
  intPart = intPart.replace(/^0+(?=\d)/, '') || '0';

  if (fracPart.length <= places) {
    const padded = fracPart.padEnd(places, '0');
    const out = places ? `${intPart}.${padded}` : intPart;
    return normalizeNegativeZero(sign, out);
  }

  const keptFrac = fracPart.slice(0, places);
  const roundDigit = fracPart[places];
  const tail = fracPart.slice(places + 1);

  const anyTailNonZero = /[1-9]/.test(tail);
  let shouldRoundUp = false;

  if (roundDigit > '5') {
    shouldRoundUp = true;
  } else if (roundDigit < '5') {
    shouldRoundUp = false;
  } else if (anyTailNonZero) {
    shouldRoundUp = true;
  } else {
    const lastKeptDigit = places > 0
      ? (keptFrac[keptFrac.length - 1] || '0')
      : intPart[intPart.length - 1];
    shouldRoundUp = Number(lastKeptDigit) % 2 === 1;
  }

  let digits = intPart + keptFrac;
  if (shouldRoundUp) digits = addOne(digits);
  if (digits.length <= places) digits = digits.padStart(places + 1, '0');

  const newInt = digits.slice(0, digits.length - places) || '0';
  const newFrac = places ? digits.slice(digits.length - places).padStart(places, '0') : '';
  const out = places ? `${newInt}.${newFrac}` : newInt;
  return normalizeNegativeZero(sign, out);
}

function addOne(digits) {
  let carry = 1;
  let out = '';
  for (let i = digits.length - 1; i >= 0; i--) {
    const n = digits.charCodeAt(i) - 48 + carry;
    if (n >= 10) {
      out = '0' + out;
      carry = 1;
    } else {
      out = String(n) + out;
      carry = 0;
    }
  }
  return carry ? '1' + out : out;
}

function normalizeNegativeZero(sign, value) {
  return /^0(?:\.0+)?$/.test(value) ? value : sign + value;
}
```

