function normalizeMinutes(value) {
  const minutes = ((value % 1440) + 1440) % 1440;
  return Object.is(minutes, -0) ? 0 : minutes;
}

function comparePointToBoundary(point, boundary, inclusive) {
  if (point < boundary) return -1;
  if (point > boundary) return 1;
  return inclusive ? 0 : 1;
}

function segmentOverlaps(aStart, aEnd, aStartInc, aEndInc, bStart, bEnd, bStartInc, bEndInc) {
  const left = Math.max(aStart, bStart);
  const right = Math.min(aEnd, bEnd);

  if (left < right) return true;
  if (left > right) return false;

  const aIncludes = left === aStart ? aStartInc : aEndInc;
  const bIncludes = left === bStart ? bStartInc : bEndInc;
  return aIncludes && bIncludes;
}

function expandInterval(startMinutes, endMinutes, startInclusive = true, endInclusive = false) {
  const start = normalizeMinutes(startMinutes);
  const end = normalizeMinutes(endMinutes);

  if (start === end) {
    if (startInclusive && endInclusive) {
      return [{ start, end: start, startInclusive: true, endInclusive: true, zeroLength: true }];
    }
    return [];
  }

  if (start < end) {
    return [{ start, end, startInclusive, endInclusive, zeroLength: false }];
  }

  return [
    { start, end: 1440, startInclusive, endInclusive: false, zeroLength: false },
    { start: 0, end, startInclusive: true, endInclusive, zeroLength: false },
  ];
}

function intervalsOverlap(a, b) {
  const aSegments = expandInterval(a.start, a.end, a.startInclusive, a.endInclusive);
  const bSegments = expandInterval(b.start, b.end, b.startInclusive, b.endInclusive);

  for (const segA of aSegments) {
    for (const segB of bSegments) {
      if (
        segmentOverlaps(
          segA.start,
          segA.end,
          segA.startInclusive,
          segA.endInclusive,
          segB.start,
          segB.end,
          segB.startInclusive,
          segB.endInclusive,
        )
      ) {
        return true;
      }
    }
  }

  return false;
}
