function parseAndNormalizeIPv6(input) {
  if (typeof input !== 'string') return { valid: false, error: 'Input must be a string' };

  const value = input.trim();
  if (!value) return { valid: false, error: 'Empty address' };

  if ((value.match(/::/g) || []).length > 1) {
    return { valid: false, error: 'IPv6 address cannot contain multiple :: compressions' };
  }

  let ipv4Tail = null;
  let head = value;

  if (value.includes('.')) {
    const lastColon = value.lastIndexOf(':');
    if (lastColon === -1) {
      return { valid: false, error: 'Invalid IPv4-mapped IPv6 form' };
    }

    const ipv4Part = value.slice(lastColon + 1);
    const parsedIPv4 = parseIPv4(ipv4Part);
    if (!parsedIPv4.valid) {
      return { valid: false, error: parsedIPv4.error };
    }

    ipv4Tail = parsedIPv4.bytes;
    head = value.slice(0, lastColon);
    if (!head.endsWith(':')) {
      return { valid: false, error: 'Invalid mixed IPv6/IPv4 form' };
    }
  }

  const hasCompression = head.includes('::');
  let parts;

  if (hasCompression) {
    const [left, right] = head.split('::');
    const leftParts = left ? left.split(':') : [];
    const rightParts = right ? right.split(':') : [];

    if ([...leftParts, ...rightParts].some(p => p.length === 0)) {
      return { valid: false, error: 'Invalid IPv6 group placement' };
    }

    const ipv4Groups = ipv4Tail ? 2 : 0;
    const missing = 8 - ipv4Groups - leftParts.length - rightParts.length;
    if (missing < 1) {
      return { valid: false, error: 'Invalid :: compression width' };
    }

    parts = [
      ...leftParts,
      ...Array(missing).fill('0'),
      ...rightParts,
    ];
  } else {
    parts = head.split(':');
    if (parts.some(p => p.length === 0)) {
      return { valid: false, error: 'Invalid IPv6 group placement' };
    }
  }

  if (ipv4Tail) {
    parts.push(
      ((ipv4Tail[0] << 8) | ipv4Tail[1]).toString(16),
      ((ipv4Tail[2] << 8) | ipv4Tail[3]).toString(16),
    );
  }

  if (parts.length !== 8) {
    return { valid: false, error: 'IPv6 address must contain exactly 8 groups' };
  }

  const groups = [];
  for (const part of parts) {
    if (!/^[0-9a-fA-F]{1,4}$/.test(part)) {
      return { valid: false, error: `Invalid IPv6 group: ${part}` };
    }
    groups.push(part.toLowerCase());
  }

  return {
    valid: true,
    groups,
    canonical: canonicalizeIPv6(groups),
  };
}

function parseIPv4(input) {
  const parts = input.split('.');
  if (parts.length !== 4) {
    return { valid: false, error: 'IPv4 tail must have 4 octets' };
  }

  const bytes = [];
  for (const part of parts) {
    if (!/^\d+$/.test(part)) {
      return { valid: false, error: `Invalid IPv4 octet: ${part}` };
    }
    if (part.length > 1 && part.startsWith('0')) {
      return { valid: false, error: `IPv4 octet has leading zero: ${part}` };
    }
    const n = Number(part);
    if (n < 0 || n > 255) {
      return { valid: false, error: `IPv4 octet out of range: ${part}` };
    }
    bytes.push(n);
  }

  return { valid: true, bytes };
}

function canonicalizeIPv6(groups) {
  const normalized = groups.map(g => g.replace(/^0+/, '') || '0');

  let bestStart = -1;
  let bestLen = 0;
  for (let i = 0; i < normalized.length; ) {
    if (normalized[i] !== '0') {
      i++;
      continue;
    }
    let j = i;
    while (j < normalized.length && normalized[j] === '0') j++;
    const len = j - i;
    if (len > bestLen && len >= 2) {
      bestStart = i;
      bestLen = len;
    }
    i = j;
  }

  if (bestStart === -1) return normalized.join(':');

  const left = normalized.slice(0, bestStart).join(':');
  const right = normalized.slice(bestStart + bestLen).join(':');

  if (!left && !right) return '::';
  if (!left) return `::${right}`;
  if (!right) return `${left}::`;
  return `${left}::${right}`;
}

// Example usage
const tests = [
  '2001:0DB8:0000:0000:0000:FF00:0042:8329',
  '2001:db8::ff00:42:8329',
  '::1',
  '::',
  '::ffff:192.168.1.1',
  '2001::db8::1',
  'GGGG::1',
];

for (const t of tests) {
  console.log(t, '=>', parseAndNormalizeIPv6(t));
}
```

Canonical output rules in this implementation:
- lowercase hex
- no leading zeros per group
- longest zero run compressed with `::`
- ties compress the first run
- IPv4-mapped forms are normalized into pure canonical IPv6 hex form, e.g. `::ffff:192.168.1.1` -> `::ffff:c0a8:101`

