class Node {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.prev = null;
    this.next = null;
  }
}

class LRUCache {
  constructor(capacity) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new Error('capacity must be a non-negative integer');
    }

    this.capacity = capacity;
    this.map = new Map();
    this.head = new Node(null, null);
    this.tail = new Node(null, null);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key) {
    const node = this.map.get(key);
    if (!node) return undefined;
    this.#moveToFront(node);
    return node.value;
  }

  set(key, value) {
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing) {
      existing.value = value;
      this.#moveToFront(existing);
      return;
    }

    const node = new Node(key, value);
    this.map.set(key, node);
    this.#insertAfterHead(node);

    if (this.map.size > this.capacity) {
      const lru = this.tail.prev;
      this.#removeNode(lru);
      this.map.delete(lru.key);
    }
  }

  has(key) {
    return this.map.has(key);
  }

  #moveToFront(node) {
    this.#removeNode(node);
    this.#insertAfterHead(node);
  }

  #insertAfterHead(node) {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next.prev = node;
    this.head.next = node;
  }

  #removeNode(node) {
    node.prev.next = node.next;
    node.next.prev = node.prev;
    node.prev = null;
    node.next = null;
  }
}

// Minimal verification
(function test() {
  const assert = (condition, message) => {
    if (!condition) throw new Error(message);
  };

  // capacity 0
  const c0 = new LRUCache(0);
  c0.set('a', 1);
  assert(c0.get('a') === undefined, 'capacity 0 should never store values');

  // capacity 1
  const c1 = new LRUCache(1);
  c1.set('a', 1);
  assert(c1.get('a') === 1, 'capacity 1 should store one value');
  c1.set('b', 2);
  assert(c1.get('a') === undefined, 'capacity 1 should evict previous key');
  assert(c1.get('b') === 2, 'capacity 1 should keep newest key');

  // repeated insert same key
  const c2 = new LRUCache(2);
  c2.set('x', 1);
  c2.set('x', 2);
  c2.set('x', 3);
  assert(c2.get('x') === 3, 'repeated insert should update value');
  assert(c2.map.size === 1, 'repeated insert should not duplicate keys');

  // falsy values
  const c3 = new LRUCache(2);
  c3.set('nil', null);
  c3.set('empty', '');
  assert(c3.has('nil'), 'null value key should still exist');
  assert(c3.has('empty'), 'empty string value key should still exist');
  assert(c3.get('nil') === null, 'should return null as stored');
  assert(c3.get('empty') === '', 'should return empty string as stored');

  console.log('All tests passed');
})();
```

This handles the edge cases directly:
- capacity `0`: nothing is stored
- capacity `1`: always keeps only the most recent key
- repeated `set` on the same key: updates in place, no duplicate entries
- stored values like `null` and `''`: preserved correctly because misses are detected by node presence, not value truthiness

