function topologicalSort(graph) {
  const state = new Map(); // 0 = unvisited, 1 = visiting, 2 = visited
  const order = [];
  const stack = [];
  const stackIndex = new Map();

  const nodes = new Set();
  for (const [node, deps = []] of Object.entries(graph)) {
    nodes.add(node);
    for (const dep of deps) nodes.add(dep);
  }

  for (const node of nodes) state.set(node, 0);

  function dfs(node) {
    state.set(node, 1);
    stackIndex.set(node, stack.length);
    stack.push(node);

    for (const neighbor of graph[node] ?? []) {
      const neighborState = state.get(neighbor) ?? 0;

      if (neighborState === 0) {
        const result = dfs(neighbor);
        if (!result.ok) return result;
      } else if (neighborState === 1) {
        const start = stackIndex.get(neighbor);
        const cycle = stack.slice(start);
        cycle.push(neighbor);
        return { ok: false, cycle };
      }
    }

    stack.pop();
    stackIndex.delete(node);
    state.set(node, 2);
    order.push(node);
    return { ok: true };
  }

  for (const node of nodes) {
    if (state.get(node) === 0) {
      const result = dfs(node);
      if (!result.ok) return result;
    }
  }

  order.reverse();
  return { ok: true, order };
}

// Example usage:
console.log(topologicalSort({
  A: ['B', 'C'],
  B: ['D'],
  C: [],
  D: []
}));
// { ok: true, order: [ 'A', 'C', 'B', 'D' ] }

console.log(topologicalSort({
  A: ['A']
}));
// { ok: false, cycle: [ 'A', 'A' ] }

console.log(topologicalSort({
  A: ['B'],
  B: ['C'],
  C: ['A'],
  D: ['E'],
  E: []
}));
// { ok: false, cycle: [ 'A', 'B', 'C', 'A' ] }
