function serializeFormData(input) {
  const pairs = [];

  const encodeKeyPart = (part) =>
    encodeURIComponent(String(part)).replace(/%5B/g, '[').replace(/%5D/g, ']');

  const encodeLiteralKey = (key) => encodeURIComponent(String(key));

  const pushPair = (key, value) => {
    let normalized;
    if (value === null) normalized = '';
    else if (value === true) normalized = 'true';
    else if (value === false) normalized = 'false';
    else normalized = String(value);

    pairs.push(`${key}=${encodeURIComponent(normalized)}`);
  };

  const visit = (value, path, topLevelLiteral = false) => {
    if (Array.isArray(value)) {
      for (const item of value) {
        const nextKey = topLevelLiteral
          ? `${path}%5B%5D`
          : `${path}[]`;
        visit(item, nextKey, topLevelLiteral);
      }
      return;
    }

    if (value && typeof value === 'object') {
      for (const [rawKey, child] of Object.entries(value)) {
        const encodedSegment = encodeLiteralKey(rawKey);
        const nextKey = path
          ? `${path}[${encodedSegment}]`
          : encodedSegment;
        visit(child, nextKey, false);
      }
      return;
    }

    if (path === '') {
      throw new TypeError('serializeFormData expects an object at the top level');
    }

    pushPair(path, value);
  };

  if (!input || typeof input !== 'object' || Array.isArray(input)) {
    throw new TypeError('serializeFormData expects a plain object');
  }

  for (const [rawKey, value] of Object.entries(input)) {
    const encodedKey = encodeLiteralKey(rawKey);
    const containsLiteralBrackets = /[\[\]]/.test(rawKey);
    visit(value, encodedKey, containsLiteralBrackets);
  }

  return pairs.join('&');
}
```

