function tokenize(input) {
  const tokens = [];
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      i += 1;
      continue;
    }

    if (ch >= '0' && ch <= '9') {
      let j = i + 1;
      while (j < input.length && input[j] >= '0' && input[j] <= '9') j += 1;
      tokens.push({ type: 'number', value: Number(input.slice(i, j)) });
      i = j;
      continue;
    }

    if (ch === '+' || ch === '-' || ch === '*' || ch === '/' || ch === '(' || ch === ')') {
      tokens.push({ type: ch });
      i += 1;
      continue;
    }

    throw new SyntaxError(`Unexpected character '${ch}' at position ${i}`);
  }

  return tokens;
}

function parseArithmetic(input) {
  const tokens = tokenize(input);
  const values = [];
  const ops = [];

  let expectOperand = true;
  let parenDepth = 0;

  const precedence = (op) => (op === '+' || op === '-' ? 1 : 2);

  const applyTopOperator = () => {
    const op = ops.pop();
    if (op === '(' || op == null) {
      throw new SyntaxError('Malformed expression');
    }
    if (values.length < 2) {
      throw new SyntaxError('Adjacent operators or missing operand');
    }

    const right = values.pop();
    const left = values.pop();
    values.push({ type: 'BinaryExpression', operator: op, left, right });
  };

  for (let i = 0; i < tokens.length; i += 1) {
    const token = tokens[i];

    if (token.type === 'number') {
      if (!expectOperand) {
        throw new SyntaxError(`Missing operator before number at token ${i}`);
      }
      values.push({ type: 'Literal', value: token.value });
      expectOperand = false;
      continue;
    }

    if (token.type === '(') {
      if (!expectOperand) {
        throw new SyntaxError(`Missing operator before '(' at token ${i}`);
      }
      ops.push('(');
      parenDepth += 1;
      expectOperand = true;
      continue;
    }

    if (token.type === ')') {
      if (expectOperand) {
        throw new SyntaxError(`Empty parentheses or trailing operator before ')' at token ${i}`);
      }

      while (ops.length && ops[ops.length - 1] !== '(') {
        applyTopOperator();
      }

      if (ops.length === 0 || ops[ops.length - 1] !== '(') {
        throw new SyntaxError(`Unmatched ')' at token ${i}`);
      }

      ops.pop();
      parenDepth -= 1;
      expectOperand = false;
      continue;
    }

    if (token.type === '+' || token.type === '-' || token.type === '*' || token.type === '/') {
      if (expectOperand) {
        throw new SyntaxError(`Adjacent operators or missing left operand at token ${i}`);
      }

      while (
        ops.length &&
        ops[ops.length - 1] !== '(' &&
        precedence(ops[ops.length - 1]) >= precedence(token.type)
      ) {
        applyTopOperator();
      }

      ops.push(token.type);
      expectOperand = true;
      continue;
    }

    throw new SyntaxError(`Unhandled token '${token.type}' at token ${i}`);
  }

  if (expectOperand) {
    throw new SyntaxError('Expression cannot end with an operator');
  }

  while (ops.length) {
    if (ops[ops.length - 1] === '(') {
      throw new SyntaxError('Unmatched '(');
    }
    applyTopOperator();
  }

  if (parenDepth !== 0 || values.length !== 1) {
    throw new SyntaxError('Malformed expression');
  }

  return values[0];
}

// Example:
const ast = parseArithmetic('1 + (2 * (3 + 4))');
console.log(JSON.stringify(ast, null, 2));
```

This uses an iterative stack-based parser, so nesting depth 50,000 is fine as long as memory allows. It rejects:

- `()`
- `(1+)`
- `1++2`
- `1 2`
- `1(+2)`
- unmatched parentheses

