function stableJsonHash(value) {
  const seen = new Map();
  let nextId = 0;

  function encode(node) {
    if (node === null) return 'null';

    const type = typeof node;

    if (type === 'number') {
      if (Number.isNaN(node)) return 'number:NaN';
      if (node === Infinity) return 'number:Infinity';
      if (node === -Infinity) return 'number:-Infinity';
      return `number:${Object.is(node, -0) ? '-0' : String(node)}`;
    }

    if (type === 'string') return `string:${JSON.stringify(node)}`;
    if (type === 'boolean') return `bool:${node}`;
    if (type === 'bigint') return `bigint:${node}n`;
    if (type === 'undefined') return 'undefined';
    if (type === 'symbol') return `symbol:${String(node.description ?? '')}`;
    if (type === 'function') return `function:${node.name || ''}`;

    if (seen.has(node)) {
      return `ref:${seen.get(node)}`;
    }

    const id = nextId++;
    seen.set(node, id);

    if (Array.isArray(node)) {
      return `array#${id}[${node.map(encode).join(',')}]`;
    }

    if (node instanceof Date) {
      return `date#${id}:${Number.isNaN(node.getTime()) ? 'Invalid' : node.toISOString()}`;
    }

    if (node instanceof RegExp) {
      return `regexp#${id}:${node.toString()}`;
    }

    const keys = Object.keys(node).sort();
    const entries = keys.map((key) => `${JSON.stringify(key)}:${encode(node[key])}`);
    return `object#${id}{${entries.join(',')}}`;
  }

  const canonical = encode(value);
  return fnv1a64(canonical);
}

function fnv1a64(input) {
  let hash = 0xcbf29ce484222325n;
  const prime = 0x100000001b3n;
  const mod = 0xffffffffffffffffn;

  for (let i = 0; i < input.length; i++) {
    hash ^= BigInt(input.charCodeAt(i));
    hash = (hash * prime) & mod;
  }

  return hash.toString(16).padStart(16, '0');
}
```

Properties:
- Object keys are sorted, so key order does not affect the hash.
- Array elements are kept in order, so array order does affect the hash.
- Circular/shared references are encoded with deterministic `ref:<id>` labels based on first traversal.
- Produces a stable 64-bit hex hash string.

Example:
```js
const a = { x: 1, y: [2, 3] };
const b = { y: [2, 3], x: 1 };
console.log(stableJsonHash(a) === stableJsonHash(b)); // true

const c = { x: 1, y: [3, 2] };
console.log(stableJsonHash(a) === stableJsonHash(c)); // false

const d = { name: 'root' };
d.self = d;
console.log(stableJsonHash(d));
```

