function diffJsonLike(left, right) {
  const changes = [];
  const leftSeen = new WeakMap();
  const rightSeen = new WeakMap();

  walk(left, right, []);
  return changes;

  function walk(a, b, path) {
    if (Object.is(a, b)) return;

    const aType = valueType(a);
    const bType = valueType(b);

    if (aType !== bType) {
      changes.push({ path: formatPath(path), kind: 'type', fromType: aType, toType: bType, from: a, to: b });
      return;
    }

    if (isPrimitiveType(aType)) {
      changes.push({ path: formatPath(path), kind: 'change', from: a, to: b });
      return;
    }

    if (aType === 'array') {
      const priorAPath = leftSeen.get(a);
      const priorBPath = rightSeen.get(b);

      if (priorAPath || priorBPath) {
        if (priorAPath !== priorBPath) {
          changes.push({
            path: formatPath(path),
            kind: 'circular',
            leftRef: priorAPath ?? null,
            rightRef: priorBPath ?? null,
          });
        }
        return;
      }

      leftSeen.set(a, formatPath(path));
      rightSeen.set(b, formatPath(path));

      const max = Math.max(a.length, b.length);
      for (let i = 0; i < max; i++) {
        const aHas = i in a;
        const bHas = i in b;
        const nextPath = path.concat(i);

        if (!aHas && !bHas) continue;
        if (!aHas) {
          changes.push({ path: formatPath(nextPath), kind: 'add', value: b[i] });
          continue;
        }
        if (!bHas) {
          changes.push({ path: formatPath(nextPath), kind: 'delete', value: a[i] });
          continue;
        }

        walk(a[i], b[i], nextPath);
      }
      return;
    }

    const priorAPath = leftSeen.get(a);
    const priorBPath = rightSeen.get(b);

    if (priorAPath || priorBPath) {
      if (priorAPath !== priorBPath) {
        changes.push({
          path: formatPath(path),
          kind: 'circular',
          leftRef: priorAPath ?? null,
          rightRef: priorBPath ?? null,
        });
      }
      return;
    }

    leftSeen.set(a, formatPath(path));
    rightSeen.set(b, formatPath(path));

    const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
    for (const key of keys) {
      const aHas = Object.prototype.hasOwnProperty.call(a, key);
      const bHas = Object.prototype.hasOwnProperty.call(b, key);
      const nextPath = path.concat(key);

      if (!aHas) {
        changes.push({ path: formatPath(nextPath), kind: 'add', value: b[key] });
        continue;
      }
      if (!bHas) {
        changes.push({ path: formatPath(nextPath), kind: 'delete', value: a[key] });
        continue;
      }

      walk(a[key], b[key], nextPath);
    }
  }
}

function valueType(value) {
  if (value === null) return 'null';
  if (Array.isArray(value)) return 'array';
  return typeof value;
}

function isPrimitiveType(type) {
  return (
    type === 'null' ||
    type === 'string' ||
    type === 'number' ||
    type === 'boolean' ||
    type === 'undefined' ||
    type === 'bigint' ||
    type === 'symbol'
  );
}

function formatPath(parts) {
  if (parts.length === 0) return '$';

  let out = '$';
  for (const part of parts) {
    if (typeof part === 'number') {
      out += `[${part}]`;
    } else if (/^[A-Za-z_$][A-Za-z0-9_$]*$/.test(part)) {
      out += `.${part}`;
    } else {
      out += `[${JSON.stringify(part)}]`;
    }
  }
  return out;
}
```

