  { path: '$.name', kind: 'change', from: 'a', to: 'b' },
  { path: '$.items[2]', kind: 'add', value: 42 },
  { path: '$.meta', kind: 'type', fromType: 'object', toType: 'null', from: { ok: true }, to: null }
]
