    JsonNode node = objectMapper.readTree(path.toFile());
    if (node == null) {
        return JsonNodeFactory.instance.objectNode();
    }
    if (!node.isObject()) {
        throw new IOException("Expected JSON object in file: " + path);
    }
    return (ObjectNode) node;
